using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly PaymentGateway _sut = new();

    // --- ChargeAsync Tests ---

    [TestMethod]
    public async Task ChargeAsync_ValidCardAndAmount_ReturnsSuccessResult()
    {
        // Act & Assert вҖ” current implementation throws NotImplementedException
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync("tok_valid_card", 50.00m));
    }

    [TestMethod]
    [DataRow("tok_visa", 0.01, DisplayName = "Minimum charge amount")]
    [DataRow("tok_mastercard", 999999.99, DisplayName = "Large charge amount")]
    [DataRow("tok_amex", 100.00, DisplayName = "Round dollar amount")]
    public async Task ChargeAsync_VariousAmounts_ThrowsNotImplemented(string token, double amount)
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(token, (decimal)amount));
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsNotImplemented()
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsNotImplemented()
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync(string.Empty, 25.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsNotImplemented()
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync("tok_test", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsNotImplemented()
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.ChargeAsync("tok_test", -10.00m));
    }

    // --- RefundAsync Tests ---

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ThrowsNotImplemented()
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync("ch_abc123"));
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsNotImplemented()
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsNotImplemented()
    {
        await Assert.ThrowsExceptionAsync<NotImplementedException>(
            () => _sut.RefundAsync(string.Empty));
    }

    // --- Record Type Tests ---

    [TestMethod]
    public void ChargeResult_Properties_AreAccessible()
    {
        var result = new ChargeResult("ch_123", true);

        Assert.AreEqual("ch_123", result.ChargeId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public void ChargeResult_Equality_WorksByValue()
    {
        var a = new ChargeResult("ch_123", true);
        var b = new ChargeResult("ch_123", true);

        Assert.AreEqual(a, b);
    }

    [TestMethod]
    public void ChargeResult_Inequality_DifferentValues()
    {
        var a = new ChargeResult("ch_123", true);
        var b = new ChargeResult("ch_456", false);

        Assert.AreNotEqual(a, b);
    }

    [TestMethod]
    public void RefundResult_Properties_AreAccessible()
    {
        var result = new RefundResult("re_789", true);

        Assert.AreEqual("re_789", result.RefundId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public void RefundResult_Equality_WorksByValue()
    {
        var a = new RefundResult("re_789", false);
        var b = new RefundResult("re_789", false);

        Assert.AreEqual(a, b);
    }

    // --- Gateway Instantiation ---

    [TestMethod]
    public void PaymentGateway_CanBeInstantiated()
    {
        var gateway = new PaymentGateway();

        Assert.IsNotNull(gateway);
    }
}

